import React, { useState } from 'react';
import { ChartContainer } from './ChartContainer';
import { OrderForm } from './OrderForm';
import { Orderbook } from './Orderbook';
import { OpenOrdersTable } from './OpenOrdersTable';
import { PositionsTable } from './PositionsTable';
import { useOpenOrders } from '../../hooks/useOpenOrders';
import { usePositions } from '../../hooks/usePositions';
import type { OrderFormProps } from './OrderForm';

export interface TradingPageProps {
  walletAddress?: string;
  inputMint?: string;
  outputMint?: string;
  inputSymbol?: string;
  outputSymbol?: string;
  tradingViewSymbol?: string;
  chartType?: 'tradingview' | 'lightweight';
  /** Manifest market address for orderbook (optional — hides orderbook if not set) */
  manifestMarket?: string;
  theme?: 'light' | 'dark';
  onSign?: (transaction: string) => Promise<string>;
  onOrderSuccess?: (orderId: string) => void;
  className?: string;
}

type BottomTab = 'positions' | 'orders' | 'orderbook';

export function TradingPage({
  walletAddress,
  inputMint = 'So11111111111111111111111111111111111111112',
  outputMint = 'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v',
  inputSymbol = 'SOL', outputSymbol = 'USDC',
  tradingViewSymbol = 'SOLUSD',
  chartType = 'tradingview',
  manifestMarket,
  theme = 'dark', onSign, onOrderSuccess,
  className = '',
}: TradingPageProps) {
  const [bottomTab, setBottomTab] = useState<BottomTab>('positions');
  const { limitOrders, dcaOrders, isLoading: ordersLoading, cancelOrder } = useOpenOrders(walletAddress ?? null);
  const { positions, isLoading: positionsLoading } = usePositions(walletAddress ?? null);

  return (
    <div className={`ct-flex ct-flex-col ct-h-full ct-min-h-screen ct-bg-[hsl(var(--cedros-background))] ${className}`}>
      {/* Top: Chart + Order Form */}
      <div className="ct-flex ct-flex-1 ct-min-h-0">
        {/* Chart (takes remaining space) */}
        <div className="ct-flex-1 ct-min-w-0 ct-border-r ct-border-[hsl(var(--cedros-border))]">
          <ChartContainer chartType={chartType} symbol={tradingViewSymbol} theme={theme} />
        </div>

        {/* Order form (right panel, desktop only) */}
        <div className="ct-hidden xl:ct-block ct-w-80 ct-flex-shrink-0 ct-overflow-y-auto">
          <OrderForm
            walletAddress={walletAddress}
            inputMint={inputMint}
            outputMint={outputMint}
            inputSymbol={inputSymbol}
            outputSymbol={outputSymbol}
            onSign={onSign}
            onSuccess={onOrderSuccess}
          />
        </div>
      </div>

      {/* Bottom: Tabs */}
      <div className="ct-border-t ct-border-[hsl(var(--cedros-border))]">
        <div className="ct-flex ct-gap-4 ct-px-4 ct-border-b ct-border-[hsl(var(--cedros-border))]">
          {(['positions', 'orders', ...(manifestMarket ? ['orderbook'] : [])] as BottomTab[]).map(t => (
            <button key={t} onClick={() => setBottomTab(t)}
              className={`ct-py-2 ct-text-sm ct-font-medium ct-border-b-2 ct-transition ct-capitalize ${
                bottomTab === t
                  ? 'ct-border-[hsl(var(--cedros-primary))] ct-text-[hsl(var(--cedros-foreground))]'
                  : 'ct-border-transparent ct-text-[hsl(var(--cedros-muted-foreground))] hover:ct-text-[hsl(var(--cedros-foreground))]'
              }`}>
              {t} {t === 'orders' && limitOrders.length > 0 && `(${limitOrders.length})`}
            </button>
          ))}
        </div>

        <div className="ct-max-h-64 ct-overflow-y-auto">
          {bottomTab === 'positions' && (
            <PositionsTable
              holdings={positions?.holdings ?? []}
              isLoading={positionsLoading}
              totalValue={positions?.totalValue}
            />
          )}
          {bottomTab === 'orders' && (
            <OpenOrdersTable
              limitOrders={limitOrders}
              dcaOrders={dcaOrders}
              isLoading={ordersLoading}
              onCancel={walletAddress ? (id) => cancelOrder(id, walletAddress) : undefined}
            />
          )}
          {bottomTab === 'orderbook' && manifestMarket && (
            <Orderbook marketAddress={manifestMarket} />
          )}
        </div>
      </div>

      {/* Mobile order form (shown below chart on small screens) */}
      <div className="xl:ct-hidden ct-p-4">
        <OrderForm
          walletAddress={walletAddress}
          inputMint={inputMint}
          outputMint={outputMint}
          inputSymbol={inputSymbol}
          outputSymbol={outputSymbol}
          onSign={onSign}
          onSuccess={onOrderSuccess}
        />
      </div>
    </div>
  );
}
