import React, { useMemo } from 'react';
import { useOrderbook } from '../../hooks/useOrderbook';
import type { OrderbookLevel } from '../../hooks/useOrderbook';
import { LoadingSpinner } from '../shared/LoadingSpinner';

export interface OrderbookProps {
  marketAddress: string;
  /** Tick size for price grouping */
  tickSize?: number;
  /** Max levels to show per side */
  maxLevels?: number;
  /** Called when user clicks a price level */
  onPriceClick?: (price: number, side: 'buy' | 'sell') => void;
  className?: string;
}

export function Orderbook({
  marketAddress, tickSize = 0.01, maxLevels = 15, onPriceClick, className = '',
}: OrderbookProps) {
  const { data, isLoading, isStreaming } = useOrderbook(marketAddress);

  const grouped = useMemo(() => {
    if (!data) return { bids: [], asks: [], maxTotal: 1, spread: 0 };

    const groupLevels = (levels: OrderbookLevel[], ascending: boolean) => {
      const map = new Map<number, OrderbookLevel>();
      for (const l of levels) {
        const gp = ascending
          ? Math.ceil(l.price / tickSize) * tickSize
          : Math.floor(l.price / tickSize) * tickSize;
        const existing = map.get(gp);
        if (existing) {
          existing.size += l.size;
          existing.total += l.total;
        } else {
          map.set(gp, { price: gp, size: l.size, total: l.total });
        }
      }
      const arr = Array.from(map.values());
      arr.sort((a, b) => ascending ? a.price - b.price : b.price - a.price);
      return arr.slice(0, maxLevels);
    };

    const bids = groupLevels(data.bids, false);
    const asks = groupLevels(data.asks, true);
    const maxTotal = Math.max(
      ...bids.map(b => b.total), ...asks.map(a => a.total), 1
    );

    return { bids, asks, maxTotal, spread: data.spread };
  }, [data, tickSize, maxLevels]);

  if (isLoading) return <div className="ct-flex ct-justify-center ct-py-8"><LoadingSpinner /></div>;
  if (!data) return <div className="ct-text-center ct-py-8 ct-text-[hsl(var(--cedros-muted-foreground))] ct-text-sm">No orderbook data</div>;

  return (
    <div className={`ct-text-sm ${className}`}>
      {/* Status indicator */}
      <div className="ct-flex ct-items-center ct-justify-between ct-px-3 ct-py-1.5 ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">
        <span>Orderbook</span>
        <span className={isStreaming ? 'ct-text-green-400' : 'ct-text-yellow-400'}>
          {isStreaming ? '● Live' : '○ Polling'}
        </span>
      </div>

      {/* Headers */}
      <div className="ct-grid ct-grid-cols-3 ct-gap-2 ct-px-3 ct-py-1.5 ct-border-b ct-border-[hsl(var(--cedros-border))] ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">
        <div>Price</div>
        <div className="ct-text-right">Size</div>
        <div className="ct-text-right">Total</div>
      </div>

      {/* Asks (sells) — reversed so lowest ask is at bottom */}
      <div className="ct-max-h-48 ct-overflow-y-auto">
        {grouped.asks.slice().reverse().map((level, i) => (
          <OrderRow key={`ask-${i}`} level={level} side="ask" maxTotal={grouped.maxTotal}
            onClick={() => onPriceClick?.(level.price, 'buy')} />
        ))}
      </div>

      {/* Spread */}
      <div className="ct-px-3 ct-py-2 ct-bg-[hsl(var(--cedros-muted))] ct-border-y ct-border-[hsl(var(--cedros-border))]">
        <div className="ct-flex ct-items-center ct-justify-between ct-text-xs">
          <span className="ct-text-[hsl(var(--cedros-muted-foreground))]">Spread</span>
          <span className="ct-font-medium ct-text-[hsl(var(--cedros-foreground))]">{grouped.spread.toFixed(3)}%</span>
        </div>
        {data.midPrice > 0 && (
          <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">
            Mid: ${data.midPrice.toFixed(4)}
          </div>
        )}
      </div>

      {/* Bids (buys) */}
      <div className="ct-max-h-48 ct-overflow-y-auto">
        {grouped.bids.map((level, i) => (
          <OrderRow key={`bid-${i}`} level={level} side="bid" maxTotal={grouped.maxTotal}
            onClick={() => onPriceClick?.(level.price, 'sell')} />
        ))}
      </div>
    </div>
  );
}

function OrderRow({ level, side, maxTotal, onClick }: {
  level: OrderbookLevel; side: 'ask' | 'bid'; maxTotal: number; onClick: () => void;
}) {
  const isAsk = side === 'ask';
  const barWidth = `${(level.total / maxTotal) * 100}%`;

  return (
    <div onClick={onClick}
      className={`ct-relative ct-px-3 ct-py-1 ct-cursor-pointer ct-transition-colors ${
        isAsk ? 'hover:ct-bg-red-500/10' : 'hover:ct-bg-green-500/10'
      }`}>
      {/* Depth bar */}
      <div className={`ct-absolute ct-inset-y-0 ct-left-0 ${isAsk ? 'ct-bg-red-500/10' : 'ct-bg-green-500/10'}`}
        style={{ width: barWidth }} />
      {/* Content */}
      <div className="ct-relative ct-grid ct-grid-cols-3 ct-gap-2">
        <div className={`ct-font-medium ${isAsk ? 'ct-text-red-400' : 'ct-text-green-400'}`}>
          {level.price.toFixed(4)}
        </div>
        <div className="ct-text-right ct-text-[hsl(var(--cedros-foreground))]">{level.size.toFixed(2)}</div>
        <div className="ct-text-right ct-text-[hsl(var(--cedros-muted-foreground))]">
          ${(level.total / 1000).toFixed(1)}K
        </div>
      </div>
    </div>
  );
}
