import { useCallback, useState } from 'react';
import { useTradeApi } from '../context/CedrosTradeProvider';
import type { TransferBuildResponse, ExecuteResult } from '../types';

export interface UseTransferReturn {
  buildResult: TransferBuildResponse | null;
  executeResult: ExecuteResult | null;
  isLoading: boolean;
  error: string | null;
  build: (sender: string, recipient: string, mint: string, amount: string, memo?: string) => Promise<TransferBuildResponse>;
  execute: (signedTransaction: string) => Promise<ExecuteResult>;
  resolveAddress: (address: string) => Promise<{ input: string; resolved: string; type: string }>;
  reset: () => void;
}

export function useTransfer(): UseTransferReturn {
  const api = useTradeApi();
  const [buildResult, setBuildResult] = useState<TransferBuildResponse | null>(null);
  const [executeResult, setExecuteResult] = useState<ExecuteResult | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const build = useCallback(async (sender: string, recipient: string, mint: string, amount: string, memo?: string) => {
    setIsLoading(true); setError(null);
    try {
      const r = await api.buildTransfer({ sender, recipient, mint, amount, memo });
      setBuildResult(r);
      return r;
    } catch (e: any) { setError(e.message); throw e; }
    finally { setIsLoading(false); }
  }, [api]);

  const execute = useCallback(async (signedTransaction: string) => {
    setIsLoading(true); setError(null);
    try {
      const r = await api.executeTransfer(signedTransaction);
      setExecuteResult(r);
      return r;
    } catch (e: any) { setError(e.message); throw e; }
    finally { setIsLoading(false); }
  }, [api]);

  const resolveAddress = useCallback(async (address: string) => {
    return api.resolveAddress(address);
  }, [api]);

  const reset = useCallback(() => {
    setBuildResult(null); setExecuteResult(null); setError(null);
  }, []);

  return { buildResult, executeResult, isLoading, error, build, execute, resolveAddress, reset };
}
