import React, { useState } from 'react';
import { useActionQueue } from '../../hooks/useActionQueue';
import { LoadingSpinner } from '../shared/LoadingSpinner';

export interface ActionQueueProps {
  walletAddress?: string;
  onSign?: (transaction: string) => Promise<string>;
  className?: string;
}

export function ActionQueue({ walletAddress, onSign, className = '' }: ActionQueueProps) {
  const { actions, isLoading, complete, dismiss } = useActionQueue(walletAddress ?? null);
  const [signingId, setSigningId] = useState<string | null>(null);

  const handleSign = async (actionId: string, transaction: string) => {
    if (!onSign) return;
    setSigningId(actionId);
    try {
      const signed = await onSign(transaction);
      await complete(actionId, signed);
    } catch { /* error shown in hook */ }
    finally { setSigningId(null); }
  };

  if (!walletAddress || actions.length === 0) return null;

  return (
    <div className={`ct-space-y-2 ${className}`}>
      <h4 className="ct-text-sm ct-font-medium ct-text-[hsl(var(--cedros-foreground))]">
        Pending Actions ({actions.length})
      </h4>
      {actions.map(a => (
        <div key={a.id} className="ct-flex ct-items-center ct-gap-3 ct-p-3 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))]">
          <div className="ct-flex-1 ct-min-w-0">
            <div className="ct-text-sm ct-text-[hsl(var(--cedros-foreground))]">{a.reason}</div>
            <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">
              Expires {new Date(a.expiresAt).toLocaleTimeString()}
            </div>
          </div>
          <div className="ct-flex ct-gap-2">
            <button onClick={() => handleSign(a.id, a.transaction)} disabled={signingId === a.id}
              className="ct-px-3 ct-py-1.5 ct-rounded ct-text-xs ct-font-medium ct-bg-[hsl(var(--cedros-primary))] ct-text-[hsl(var(--cedros-primary-foreground))] hover:ct-opacity-90 disabled:ct-opacity-50">
              {signingId === a.id ? <LoadingSpinner className="ct-h-3 ct-w-3" /> : 'Sign'}
            </button>
            <button onClick={() => dismiss(a.id)}
              className="ct-px-3 ct-py-1.5 ct-rounded ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))] hover:ct-text-[hsl(var(--cedros-foreground))]">
              Dismiss
            </button>
          </div>
        </div>
      ))}
    </div>
  );
}

export interface ActionNotificationBadgeProps {
  walletAddress?: string;
  onClick?: () => void;
  className?: string;
}

export function ActionNotificationBadge({ walletAddress, onClick, className = '' }: ActionNotificationBadgeProps) {
  const { count } = useActionQueue(walletAddress ?? null);
  if (count === 0) return null;

  return (
    <button onClick={onClick}
      className={`ct-relative ct-inline-flex ct-items-center ct-justify-center ct-px-2 ct-py-1 ct-rounded-full ct-text-xs ct-font-medium ct-bg-red-500 ct-text-white ct-animate-pulse ${className}`}>
      {count}
    </button>
  );
}
