import { useCallback, useEffect, useState } from 'react';
import { useTradeApi } from '../context/CedrosTradeProvider';
import type { PositionsResponse } from '../types';

export interface UsePositionsReturn {
  positions: PositionsResponse | null;
  isLoading: boolean;
  error: string | null;
  refresh: () => Promise<void>;
}

export function usePositions(walletAddress: string | null): UsePositionsReturn {
  const api = useTradeApi();
  const [positions, setPositions] = useState<PositionsResponse | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const refresh = useCallback(async () => {
    if (!walletAddress) return;
    setIsLoading(true); setError(null);
    try {
      setPositions(await api.getPositions(walletAddress));
    } catch (e: any) { setError(e.message); }
    finally { setIsLoading(false); }
  }, [api, walletAddress]);

  useEffect(() => { refresh(); }, [refresh]);

  return { positions, isLoading, error, refresh };
}
