import React from 'react';

export interface ErrorMessageProps {
  message: string | null;
  className?: string;
  onDismiss?: () => void;
}

export function ErrorMessage({ message, className = '', onDismiss }: ErrorMessageProps) {
  if (!message) return null;
  return (
    <div className={`ct-rounded-cedros ct-bg-red-500/10 ct-border ct-border-red-500/20 ct-px-3 ct-py-2 ct-text-sm ct-text-red-400 ct-flex ct-items-center ct-justify-between ${className}`}>
      <span>{message}</span>
      {onDismiss && (
        <button onClick={onDismiss} className="ct-ml-2 ct-text-red-400 hover:ct-text-red-300 ct-text-lg ct-leading-none">&times;</button>
      )}
    </div>
  );
}
