import { useCallback, useEffect, useRef, useState } from 'react';
import { useTradeContext } from '../context/CedrosTradeProvider';

export interface OrderbookLevel {
  price: number;
  size: number;
  total: number;
}

export interface OrderbookData {
  market: string;
  baseMint: string;
  quoteMint: string;
  bids: OrderbookLevel[];
  asks: OrderbookLevel[];
  spread: number;
  midPrice: number;
}

export interface UseOrderbookReturn {
  data: OrderbookData | null;
  isLoading: boolean;
  error: string | null;
  isStreaming: boolean;
}

export function useOrderbook(marketAddress: string | null, streaming = true): UseOrderbookReturn {
  const { config } = useTradeContext();
  const [data, setData] = useState<OrderbookData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isStreaming, setIsStreaming] = useState(false);
  const wsRef = useRef<WebSocket | null>(null);

  // REST fallback
  const fetchOnce = useCallback(async () => {
    if (!marketAddress) return;
    setIsLoading(true);
    try {
      const resp = await fetch(`${config.serverUrl}/orderbook/${marketAddress}`);
      if (!resp.ok) throw new Error('Failed to fetch orderbook');
      setData(await resp.json());
    } catch (e: any) { setError(e.message); }
    finally { setIsLoading(false); }
  }, [config.serverUrl, marketAddress]);

  // WebSocket streaming
  useEffect(() => {
    if (!marketAddress || !streaming) { fetchOnce(); return; }

    const wsUrl = config.serverUrl.replace(/^http/, 'ws') + `/ws/orderbook/${marketAddress}`;
    const ws = new WebSocket(wsUrl);
    wsRef.current = ws;

    ws.onopen = () => setIsStreaming(true);
    ws.onmessage = (event) => {
      try { setData(JSON.parse(event.data)); }
      catch { /* ignore parse errors */ }
    };
    ws.onerror = () => { setIsStreaming(false); fetchOnce(); };
    ws.onclose = () => setIsStreaming(false);

    return () => { ws.close(); wsRef.current = null; };
  }, [marketAddress, streaming, config.serverUrl, fetchOnce]);

  return { data, isLoading, error, isStreaming };
}
