import React, { useState } from 'react';

export interface SlippageControlProps {
  value: number;
  onChange: (bps: number) => void;
  className?: string;
}

const PRESETS = [
  { label: '0.1%', bps: 10 },
  { label: '0.5%', bps: 50 },
  { label: '1.0%', bps: 100 },
];

export function SlippageControl({ value, onChange, className = '' }: SlippageControlProps) {
  const [isCustom, setIsCustom] = useState(!PRESETS.some(p => p.bps === value));
  const [customInput, setCustomInput] = useState(isCustom ? (value / 100).toString() : '');

  const handleCustomChange = (input: string) => {
    setCustomInput(input);
    const parsed = parseFloat(input);
    if (!isNaN(parsed) && parsed > 0 && parsed <= 50) {
      onChange(Math.round(parsed * 100));
    }
  };

  return (
    <div className={`ct-flex ct-items-center ct-gap-2 ${className}`}>
      <span className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Slippage</span>
      <div className="ct-flex ct-gap-1">
        {PRESETS.map(p => (
          <button key={p.bps} onClick={() => { onChange(p.bps); setIsCustom(false); }}
            className={`ct-px-2 ct-py-1 ct-rounded ct-text-xs ct-transition ${
              value === p.bps && !isCustom
                ? 'ct-bg-[hsl(var(--cedros-primary))] ct-text-[hsl(var(--cedros-primary-foreground))]'
                : 'ct-bg-[hsl(var(--cedros-muted))] ct-text-[hsl(var(--cedros-muted-foreground))] hover:ct-bg-[hsl(var(--cedros-border))]'
            }`}>
            {p.label}
          </button>
        ))}
        <input
          type="text"
          placeholder="Custom"
          value={isCustom ? customInput : ''}
          onFocus={() => setIsCustom(true)}
          onChange={e => handleCustomChange(e.target.value)}
          className="ct-w-16 ct-px-2 ct-py-1 ct-rounded ct-text-xs ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none focus:ct-ring-1 focus:ct-ring-[hsl(var(--cedros-ring))]"
        />
        <span className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">%</span>
      </div>
    </div>
  );
}
