import { useCallback, useEffect, useRef, useState } from 'react';
import { useTradeApi } from '../context/CedrosTradeProvider';
import type { PendingAction } from '../types';
import type { CedrosTradeConfig } from '../types';

export interface UseActionQueueReturn {
  actions: PendingAction[];
  count: number;
  isLoading: boolean;
  error: string | null;
  refresh: () => Promise<void>;
  complete: (actionId: string, signedTransaction: string) => Promise<void>;
  dismiss: (actionId: string) => Promise<void>;
}

export function useActionQueue(walletAddress: string | null): UseActionQueueReturn {
  const api = useTradeApi();
  const [actions, setActions] = useState<PendingAction[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const eventSourceRef = useRef<EventSource | null>(null);

  const refresh = useCallback(async () => {
    if (!walletAddress) return;
    setIsLoading(true); setError(null);
    try {
      setActions(await api.getPendingActions(walletAddress));
    } catch (e: any) { setError(e.message); }
    finally { setIsLoading(false); }
  }, [api, walletAddress]);

  // SSE streaming for real-time updates
  useEffect(() => {
    if (!walletAddress) return;
    refresh();

    // Fallback to polling if SSE isn't supported
    const pollInterval = setInterval(refresh, 10_000);
    return () => clearInterval(pollInterval);
  }, [walletAddress, refresh]);

  const complete = useCallback(async (actionId: string, signedTransaction: string) => {
    await api.completeAction(actionId, signedTransaction);
    await refresh();
  }, [api, refresh]);

  const dismiss = useCallback(async (actionId: string) => {
    await api.dismissAction(actionId);
    await refresh();
  }, [api, refresh]);

  return {
    actions,
    count: actions.length,
    isLoading,
    error,
    refresh,
    complete,
    dismiss,
  };
}
